import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"OAuth & Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"oauth-authentication.md","filePath":"oauth-authentication.md"}'),i={name:"oauth-authentication.md"};function r(d,t,s,c,l,h){return a(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="oauth-authentication" tabindex="-1">OAuth &amp; Authentication <a class="header-anchor" href="#oauth-authentication" aria-label="Permalink to &quot;OAuth &amp; Authentication&quot;">​</a></h1><p>Proxy Smart acts as an OAuth 2.0 / OpenID Connect proxy between SMART apps and Keycloak. All authentication traffic flows through the <code>/auth</code> endpoints, which validate, enrich, and forward requests to the underlying Keycloak realm.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SMART App  ──►  /auth/authorize  ──►  Keycloak /auth endpoint</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>SMART App  ◄──  redirect with code  ◄────┘</span></span>
<span class="line"><span>                                          </span></span>
<span class="line"><span>SMART App  ──►  /auth/token      ──►  Keycloak /token endpoint</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>SMART App  ◄──  access_token     ◄────────┘</span></span>
<span class="line"><span>                                          </span></span>
<span class="line"><span>SMART App  ──►  /proxy-smart/…   ──►  FHIR Server (with validated token)</span></span></code></pre></div><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><h3 id="discovery" tabindex="-1">Discovery <a class="header-anchor" href="#discovery" aria-label="Permalink to &quot;Discovery&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET /auth/.well-known/openid-configuration</code></td><td>Proxies Keycloak&#39;s OIDC discovery metadata</td></tr><tr><td><code>GET /auth/.well-known/oauth-authorization-server</code></td><td>OAuth 2.0 AS Metadata (RFC 8414)</td></tr><tr><td><code>GET /auth/config</code></td><td>Returns Keycloak connectivity status and realm info</td></tr><tr><td><code>GET /.well-known/oauth-protected-resource</code></td><td>RFC 9728 Protected Resource Metadata for MCP clients</td></tr><tr><td><code>GET /.well-known/jwks.json</code></td><td>JSON Web Key Set for token verification</td></tr></tbody></table><h3 id="authorization-flow" tabindex="-1">Authorization Flow <a class="header-anchor" href="#authorization-flow" aria-label="Permalink to &quot;Authorization Flow&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET /auth/authorize</code></td><td>Redirects to Keycloak&#39;s authorization endpoint</td></tr><tr><td><code>GET /auth/login</code></td><td>Simplified login redirect with sensible defaults for UI apps</td></tr><tr><td><code>GET /auth/logout</code></td><td>Proxies logout to Keycloak with <code>id_token_hint</code> and redirect</td></tr><tr><td><code>GET /auth/identity-providers</code></td><td>Public list of enabled identity providers for login pages</td></tr></tbody></table><h3 id="token-operations" tabindex="-1">Token Operations <a class="header-anchor" href="#token-operations" aria-label="Permalink to &quot;Token Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>POST /auth/token</code></td><td>Proxies token requests to Keycloak (authorization code, refresh, client credentials)</td></tr><tr><td><code>POST /auth/introspect</code></td><td>Token introspection with SMART launch context enrichment</td></tr><tr><td><code>GET /auth/userinfo</code></td><td>UserInfo endpoint with authorization_details generation</td></tr></tbody></table><h3 id="dynamic-client-registration" tabindex="-1">Dynamic Client Registration <a class="header-anchor" href="#dynamic-client-registration" aria-label="Permalink to &quot;Dynamic Client Registration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>POST /auth/register</code></td><td>RFC 7591 Dynamic Client Registration</td></tr></tbody></table><h2 id="authorization-flow-details" tabindex="-1">Authorization Flow Details <a class="header-anchor" href="#authorization-flow-details" aria-label="Permalink to &quot;Authorization Flow Details&quot;">​</a></h2><h3 id="smart-app-launch" tabindex="-1">SMART App Launch <a class="header-anchor" href="#smart-app-launch" aria-label="Permalink to &quot;SMART App Launch&quot;">​</a></h3><ol><li><p><strong>App redirects to <code>/auth/authorize</code></strong> with standard OAuth parameters plus SMART-specific:</p><ul><li><code>aud</code> — the FHIR server URL the app wants to access (validated against configured servers)</li><li><code>scope</code> — SMART scopes like <code>launch/patient patient/*.read openid fhirUser</code></li><li><code>launch</code> — EHR launch token (for EHR launch flow)</li></ul></li><li><p><strong>Audience validation</strong> — the proxy validates the <code>aud</code> parameter matches a configured FHIR endpoint, preventing token leakage to unauthorized servers (SMART App Launch 2.2.0 requirement).</p></li><li><p><strong>Keycloak handles authentication</strong> — user logs in, consents to scopes, Keycloak redirects back with an authorization code.</p></li><li><p><strong>App exchanges code at <code>/auth/token</code></strong> — the proxy forwards the token request to Keycloak. The response includes SMART launch context claims (patient, encounter, fhirUser) injected by Keycloak scope mappers.</p></li></ol><h3 id="supported-grant-types" tabindex="-1">Supported Grant Types <a class="header-anchor" href="#supported-grant-types" aria-label="Permalink to &quot;Supported Grant Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Grant Type</th><th>Use Case</th></tr></thead><tbody><tr><td><code>authorization_code</code></td><td>Standard SMART App Launch (EHR and standalone)</td></tr><tr><td><code>refresh_token</code></td><td>Token refresh</td></tr><tr><td><code>client_credentials</code></td><td>Backend Services (with JWT client assertion)</td></tr><tr><td><code>password</code></td><td>Resource Owner Password (admin tools only)</td></tr><tr><td>Token Exchange (RFC 8693)</td><td>Subject token exchange for delegated access</td></tr></tbody></table><h3 id="backend-services" tabindex="-1">Backend Services <a class="header-anchor" href="#backend-services" aria-label="Permalink to &quot;Backend Services&quot;">​</a></h3><p>For system-to-system access without user interaction:</p><ul><li>Uses <code>client_credentials</code> grant with <code>client_assertion_type=urn:ietf:params:oauth:client-assertion-type:jwt-bearer</code></li><li>Client authenticates with a signed JWT containing <code>system/*.read</code> scopes</li><li>No user context — suitable for bulk data, analytics, and integration engines</li></ul><h3 id="token-introspection" tabindex="-1">Token Introspection <a class="header-anchor" href="#token-introspection" aria-label="Permalink to &quot;Token Introspection&quot;">​</a></h3><p><code>POST /auth/introspect</code> enriches Keycloak&#39;s introspection response with SMART-specific fields:</p><ul><li>Generates <code>authorization_details</code> from token claims and configured FHIR servers</li><li>Includes FHIR server locations, versions, patient context, and granted scopes</li><li>Follows the SMART on FHIR authorization details type (<code>smart_on_fhir</code>)</li></ul><h3 id="userinfo" tabindex="-1">UserInfo <a class="header-anchor" href="#userinfo" aria-label="Permalink to &quot;UserInfo&quot;">​</a></h3><p><code>GET /auth/userinfo</code> returns the standard OIDC UserInfo response plus <code>authorization_details</code> generated from the token&#39;s SMART claims and configured FHIR server endpoints.</p><h2 id="keycloak-unavailability" tabindex="-1">Keycloak Unavailability <a class="header-anchor" href="#keycloak-unavailability" aria-label="Permalink to &quot;Keycloak Unavailability&quot;">​</a></h2><p>If Keycloak is unreachable when a user tries to authenticate, the proxy returns a friendly HTML error page (HTTP 503) with a retry button instead of a raw browser connection error. This applies to <code>/auth/authorize</code> and <code>/auth/login</code>.</p><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>KEYCLOAK_BASE_URL</code></td><td>Internal Keycloak URL</td><td>—</td></tr><tr><td><code>KEYCLOAK_PUBLIC_URL</code></td><td>Browser-facing Keycloak URL (if different from internal)</td><td>derives from <code>KEYCLOAK_BASE_URL</code></td></tr><tr><td><code>KEYCLOAK_REALM</code></td><td>Keycloak realm name</td><td>—</td></tr><tr><td><code>KEYCLOAK_ADMIN_CLIENT_ID</code></td><td>Service account client ID for admin API calls</td><td>—</td></tr><tr><td><code>KEYCLOAK_ADMIN_CLIENT_SECRET</code></td><td>Service account client secret</td><td>—</td></tr><tr><td><code>KEYCLOAK_DOMAIN</code></td><td>Domain override for public URL generation</td><td>—</td></tr></tbody></table>`,30)])])}const b=e(i,[["render",r]]);export{u as __pageData,b as default};
